INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(1, 'Daily Routines', 'الروتين اليومي', 'https://www.youtube.com/watch?v=eUXkj6j6Ezw', 'Daily Routine in English', 'English with Lucy', 5, 'تعلم كيف تصف روتينك اليومي بالإنجليزية', 'mcq', '[{"question":"What time does she wake up?","question_ar":"متى تستيقظ؟","options":["6:00","7:00","8:00","9:00"],"correct_answer":1,"explanation":"She says she wakes up at 7 AM"},{"question":"What does she eat for breakfast?","question_ar":"ماذا تأكل في الفطور؟","options":["eggs","cereal","toast","pancakes"],"correct_answer":2,"explanation":"She mentions having toast for breakfast"},{"question":"How does she go to work?","question_ar":"كيف تذهب إلى العمل؟","options":["by car","by bus","by train","walking"],"correct_answer":1,"explanation":"She takes the bus to work"},{"question":"What time does she finish work?","question_ar":"متى تنتهي من العمل؟","options":["3 PM","4 PM","5 PM","6 PM"],"correct_answer":2,"explanation":"She finishes work at 5 PM"}]'),
(1, 'Greetings and Introductions', 'التحيات والتعريف بالنفس', 'https://www.youtube.com/watch?v=oLqoHMb4Cxk', 'How to Greet People in English', 'BBC Learning English', 4, 'تعلم كيف تحيي الناس وتعرّف بنفسك', 'mcq', '[{"question":"What is the first greeting they teach?","question_ar":"ما هي أول تحية تعلموها؟","options":["Good morning","Hello","Hi","Hey"],"correct_answer":1,"explanation":"They start with Hello as the most common greeting"},{"question":"When do you say Good morning?","question_ar":"متى تقول Good morning؟","options":["At night","In the afternoon","Before 12 PM","All day"],"correct_answer":2,"explanation":"Good morning is used before noon"},{"question":"What do you say when you meet someone new?","question_ar":"ماذا تقول عندما تقابل شخصاً جديداً؟","options":["Goodbye","Nice to meet you","See you later","Good night"],"correct_answer":1,"explanation":"Nice to meet you is the standard phrase for first meetings"}]'),
(1, 'Colors and Numbers', 'الألوان والأرقام', 'https://www.youtube.com/watch?v=Imc6CFhz0Bk', 'Learn English Colors and Numbers', 'JenniferESL', 6, 'تعلم الألوان والأرقام بالإنجليزية', 'mcq', '[{"question":"What color is the sky?","question_ar":"ما لون السماء؟","options":["red","green","blue","yellow"],"correct_answer":2,"explanation":"The sky is blue"},{"question":"How many colors are in a rainbow?","question_ar":"كم لون في قوس القزح؟","options":["5","6","7","8"],"correct_answer":2,"explanation":"A rainbow has 7 colors"},{"question":"What comes after fourteen?","question_ar":"ماذا يأتي بعد أربعة عشر؟","options":["thirteen","fifteen","sixteen","twelve"],"correct_answer":1,"explanation":"Fifteen comes after fourteen"}]');
INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(2, 'At the Restaurant', 'في المطعم', 'https://www.youtube.com/watch?v=CQseyHitwkM', 'Restaurant English Conversations', 'English with Lucy', 6, 'تعلم كيف تطلب الطعام في المطعم', 'mcq', '[{"question":"What did the customer order first?","question_ar":"ماذا طلب الزبون أولاً؟","options":["soup","salad","bread","water"],"correct_answer":3,"explanation":"The customer asked for water first"},{"question":"How did the customer describe the steak?","question_ar":"كيف وصف الزبون الستيك؟","options":["rare","medium","well-done","overcooked"],"correct_answer":1,"explanation":"The customer ordered medium steak"},{"question":"What was the total bill?","question_ar":"كم كانت الفاتورة الإجمالية؟","options":["$15","$20","$25","$30"],"correct_answer":2,"explanation":"The total came to $25"},{"question":"Did the customer leave a tip?","question_ar":"هل ترك الزبون إكرامية؟","options":["Yes, 10%","Yes, 15%","Yes, 20%","No"],"correct_answer":1,"explanation":"The customer left a 15% tip"}]'),
(2, 'Shopping for Clothes', 'التسوق لشراء الملابس', 'https://www.youtube.com/watch?v=p2K0Hz-A0xg', 'Shopping English Vocabulary', 'Oxford Online English', 7, 'تعلم مفردات التسوق والملابس', 'mcq', '[{"question":"What size did the customer ask for?","question_ar":"ما المقاس الذي طلبه الزبون؟","options":["small","medium","large","extra large"],"correct_answer":1,"explanation":"The customer asked for medium size"},{"question":"What color shirt did they choose?","question_ar":"ما لون القميص الذي اختاروه؟","options":["white","black","blue","red"],"correct_answer":2,"explanation":"They chose a blue shirt"},{"question":"How much was the discount?","question_ar":"كم كان التخفيض؟","options":["10%","20%","30%","50%"],"correct_answer":1,"explanation":"There was a 20% discount"},{"question":"How did the customer pay?","question_ar":"كيف دفع الزبون؟","options":["cash","credit card","debit card","gift card"],"correct_answer":1,"explanation":"The customer paid by credit card"}]'),
(2, 'Asking for Directions', 'السؤال عن الاتجاهات', 'https://www.youtube.com/watch?v=D3GCuCCdJEA', 'How to Ask for Directions in English', 'BBC Learning English', 5, 'تعلم كيف تسأل عن الطريق بالإنجليزية', 'mcq', '[{"question":"Where did the person want to go?","question_ar":"أين أراد الشخص أن يذهب؟","options":["the bank","the hospital","the post office","the library"],"correct_answer":2,"explanation":"They wanted to find the post office"},{"question":"Which direction should they turn?","question_ar":"في أي اتجاه يجب أن يلتفوا؟","options":["left","right","straight","back"],"correct_answer":0,"explanation":"They need to turn left at the traffic light"},{"question":"How far is it from here?","question_ar":"كم يبعد من هنا؟","options":["2 minutes","5 minutes","10 minutes","15 minutes"],"correct_answer":1,"explanation":"It is about 5 minutes walk"}]');
INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(3, 'Job Interview Tips', 'نصائح لمقابلة العمل', 'https://www.youtube.com/watch?v=kayOhGRcNt4', 'Job Interview Tips', 'EngVid', 8, 'نصائح مهمة لنجاح مقابلة العمل', 'mcq', '[{"question":"What is the first thing you should do in an interview?","question_ar":"ما أول شيء يجب فعله في المقابلة؟","options":["Ask about salary","Make eye contact and smile","Talk about hobbies","Show your resume"],"correct_answer":1,"explanation":"Making eye contact and smiling creates a good first impression"},{"question":"What should you research before the interview?","question_ar":"ماذا يجب أن تبحث عنه قبل المقابلة؟","options":["The weather","The company","The interviewer age","The office location only"],"correct_answer":1,"explanation":"You should research the company before your interview"},{"question":"How should you answer Tell me about yourself?","question_ar":"كيف تجيب على أخبرني عن نفسك؟","options":["Tell your life story","Focus on professional experience","Talk about family","Describe your hobbies"],"correct_answer":1,"explanation":"Focus on relevant professional experience"},{"question":"What should you NOT do during an interview?","question_ar":"ما الذي يجب ألا تفعله في المقابلة؟","options":["Ask questions","Use phone","Take notes","Be early"],"correct_answer":1,"explanation":"Using your phone during an interview is unprofessional"},{"question":"When should you follow up after an interview?","question_ar":"متى يجب المتابعة بعد المقابلة؟","options":["Same day","Within 24 hours","After a week","Never"],"correct_answer":1,"explanation":"Send a thank-you email within 24 hours"}]'),
(3, 'Travel and Tourism', 'السفر والسياحة', 'https://www.youtube.com/watch?v=7AHsaIJ6PGY', 'Travel English Essentials', 'Oxford Online English', 7, 'عبارات أساسية للسفر بالإنجليزية', 'mcq', '[{"question":"What should you say at hotel check-in?","question_ar":"ماذا تقول عند تسجيل الوصول في الفندق؟","options":["I want room","I have a reservation under...","Give me key","Room now please"],"correct_answer":1,"explanation":"I have a reservation under [name] is the polite way"},{"question":"How do you ask about checkout time?","question_ar":"كيف تسأل عن وقت تسليم الغرفة؟","options":["When I leave?","What time is checkout?","I go when?","Checkout what time?"],"correct_answer":1,"explanation":"What time is checkout? is the correct form"},{"question":"What phrase is used at the airport?","question_ar":"ما العبارة المستخدمة في المطار؟","options":["I want to fly","Where is my plane?","Id like to check in for my flight","Take me to plane"],"correct_answer":2,"explanation":"Id like to check in for my flight is standard airport English"},{"question":"How do you ask for recommendations?","question_ar":"كيف تطلب توصيات؟","options":["Tell me good place","Could you recommend a good restaurant?","Where food?","I need eat"],"correct_answer":1,"explanation":"Could you recommend is a polite way to ask"},{"question":"What does Could I have the bill mean?","question_ar":"ماذا تعني Could I have the bill؟","options":["Can I pay?","I want money","Request the check","I disagree"],"correct_answer":2,"explanation":"Could I have the bill means requesting the check/receipt for payment"}]');
INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(4, 'Technology and Society', 'التكنولوجيا والمجتمع', 'https://www.youtube.com/watch?v=6Af6b_wyiwI', 'How Technology is Changing Society', 'TED-Ed', 5, 'كيف تغير التكنولوجيا مجتمعنا', 'mcq', '[{"question":"What is the main argument of the video?","question_ar":"ما الحجة الرئيسية في الفيديو؟","options":["Technology is always bad","Technology changes how we communicate","We should stop using technology","Technology is only for young people"],"correct_answer":1,"explanation":"The video argues that technology fundamentally changes human communication patterns"},{"question":"What example is given about social media?","question_ar":"ما المثال المعطى عن وسائل التواصل؟","options":["It wastes time","It connects people globally","It is dangerous","It should be banned"],"correct_answer":1,"explanation":"Social media is presented as a tool that connects people across the globe"},{"question":"What concern does the speaker raise?","question_ar":"ما القلق الذي يطرحه المتحدث؟","options":["Cost of technology","Privacy and data security","Speed of internet","Color of devices"],"correct_answer":1,"explanation":"The speaker raises concerns about privacy and data security"},{"question":"What solution is proposed?","question_ar":"ما الحل المقترح؟","options":["Ban all technology","Digital literacy education","Use less internet","Only use phones"],"correct_answer":1,"explanation":"Digital literacy education is proposed as a solution"},{"question":"What is the speakers overall tone?","question_ar":"ما نبرة المتحدث العامة؟","options":["Angry","Balanced and thoughtful","Very negative","Extremely positive"],"correct_answer":1,"explanation":"The speaker maintains a balanced, thoughtful perspective"}]'),
(4, 'Environmental Issues', 'القضايا البيئية', 'https://www.youtube.com/watch?v=eRLJrzAlL_w', 'Climate Change Explained', 'Kurzgesagt', 6, 'شرح مبسط لتغير المناخ', 'mcq', '[{"question":"What is the greenhouse effect?","question_ar":"ما هو تأثير الاحتباس الحراري؟","options":["Plants growing in greenhouses","Gases trapping heat in atmosphere","Green color in the sky","Farming technique"],"correct_answer":1,"explanation":"The greenhouse effect refers to gases trapping heat in the atmosphere"},{"question":"Which gas is primarily responsible?","question_ar":"أي غاز هو المسؤول الرئيسي؟","options":["Oxygen","Nitrogen","Carbon dioxide","Hydrogen"],"correct_answer":2,"explanation":"Carbon dioxide (CO2) is the primary greenhouse gas"},{"question":"What human activity contributes most?","question_ar":"أي نشاط بشري يساهم أكثر؟","options":["Cooking","Burning fossil fuels","Swimming","Reading"],"correct_answer":1,"explanation":"Burning fossil fuels is the largest contributor to CO2 emissions"},{"question":"What consequence is mentioned?","question_ar":"ما النتيجة المذكورة؟","options":["More rain everywhere","Rising sea levels","Colder winters","More forests"],"correct_answer":1,"explanation":"Rising sea levels due to melting ice caps is a key consequence"},{"question":"What can individuals do?","question_ar":"ماذا يمكن للأفراد فعله؟","options":["Nothing","Reduce energy consumption","Only recycle","Move to another planet"],"correct_answer":1,"explanation":"Reducing energy consumption is one way individuals can help"},{"question":"What is the videos conclusion?","question_ar":"ما خاتمة الفيديو؟","options":["Give up hope","Collective action is needed","Technology will fix everything","Its too late"],"correct_answer":1,"explanation":"The video concludes that collective action from governments and individuals is needed"}]');
INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(5, 'The Science of Happiness', 'علم السعادة', 'https://www.youtube.com/watch?v=GXy__kBVq1M', 'The Surprising Science of Happiness', 'TED Talks', 8, 'ما يقوله العلم عن السعادة الحقيقية', 'mcq', '[{"question":"What is synthetic happiness according to the speaker?","question_ar":"ما هي السعادة المصطنعة حسب المتحدث؟","options":["Fake happiness","Happiness we create when we dont get what we want","Happiness from buying things","Pretending to be happy"],"correct_answer":1,"explanation":"Synthetic happiness is the happiness we manufacture when our desires are not met"},{"question":"How does the speaker challenge conventional wisdom?","question_ar":"كيف يتحدى المتحدث الحكمة التقليدية؟","options":["By using statistics","By showing synthetic happiness is as real as natural happiness","By criticizing society","By telling jokes"],"correct_answer":1,"explanation":"The speaker presents research showing synthetic happiness is equally genuine"},{"question":"What role does choice play in happiness?","question_ar":"ما دور الاختيار في السعادة؟","options":["More choices always mean more happiness","Too many choices can decrease satisfaction","Choice does not matter","Only one choice is best"],"correct_answer":1,"explanation":"The paradox of choice — too many options can actually reduce satisfaction"},{"question":"What evidence does the speaker present?","question_ar":"ما الدليل الذي يقدمه المتحدث؟","options":["Personal stories only","Psychological experiments","Religious texts","Historical events"],"correct_answer":1,"explanation":"The speaker presents psychological experiments and research data"},{"question":"What is the main takeaway?","question_ar":"ما الرسالة الرئيسية؟","options":["Buy more things","Our psychological immune system helps us find happiness","Happiness is impossible","Only lucky people are happy"],"correct_answer":1,"explanation":"Our psychological immune system helps us adapt and find happiness"},{"question":"How does this relate to decision-making?","question_ar":"كيف يرتبط هذا باتخاذ القرارات؟","options":["Make decisions quickly","Reversible decisions make us less happy than irreversible ones","Never make decisions","Let others decide"],"correct_answer":1,"explanation":"Irreversible decisions tend to make us happier because we commit to them"},{"question":"What implication does this have for society?","question_ar":"ما الأثر المترتب على المجتمع؟","options":["We should limit freedom","Consumer culture may not increase happiness","Nothing changes","Everyone should be the same"],"correct_answer":1,"explanation":"The findings suggest that consumer culture and endless choice may not increase overall happiness"}]');
INSERT INTO curriculum_listening_exercises (level, title_en, title_ar, youtube_url, youtube_title, channel, duration_minutes, description_ar, mode, questions) VALUES
(6, 'IELTS Listening Practice — Academic', 'تمرين استماع آيلتس — أكاديمي', 'https://www.youtube.com/watch?v=OY7a0R2GCVY', 'IELTS Listening Practice Test', 'IELTS Liz', 6, 'تمرين استماع بأسلوب اختبار آيلتس الأكاديمي', 'mcq', '[{"question":"What is the main purpose of the lecture?","question_ar":"ما الهدف الرئيسي من المحاضرة؟","options":["To entertain","To inform about a research methodology","To criticize a theory","To compare two studies"],"correct_answer":1,"explanation":"The lecture aims to inform students about research methodology"},{"question":"According to the speaker, what is the limitation of the study?","question_ar":"حسب المتحدث ما هي محدودية الدراسة؟","options":["Too many participants","Sample size was small","It was too expensive","It took too long"],"correct_answer":1,"explanation":"The small sample size is identified as a key limitation"},{"question":"What does the speaker recommend for future research?","question_ar":"ماذا يوصي المتحدث للبحث المستقبلي؟","options":["Stop researching","Larger longitudinal studies","Only use surveys","Ignore previous findings"],"correct_answer":1,"explanation":"Larger longitudinal studies are recommended"},{"question":"How does the speaker characterize the findings?","question_ar":"كيف يصف المتحدث النتائج؟","options":["Definitive","Preliminary but promising","Completely wrong","Outdated"],"correct_answer":1,"explanation":"The findings are described as preliminary but promising"},{"question":"What academic skill is being tested here?","question_ar":"ما المهارة الأكاديمية التي يتم اختبارها؟","options":["Memorization","Understanding academic discourse","Speed reading","Creative writing"],"correct_answer":1,"explanation":"Understanding academic discourse and extracting key information"},{"question":"What transition phrase indicates a new point?","question_ar":"ما عبارة الانتقال التي تشير إلى نقطة جديدة؟","options":["And then","Moving on to the next aspect","So yeah","Like I said"],"correct_answer":1,"explanation":"Moving on to the next aspect is a formal academic transition phrase"},{"question":"What is the speakers attitude toward the topic?","question_ar":"ما موقف المتحدث تجاه الموضوع؟","options":["Dismissive","Objective and analytical","Emotional","Sarcastic"],"correct_answer":1,"explanation":"The speaker maintains an objective, analytical academic tone"},{"question":"Which note-taking strategy would be most effective here?","question_ar":"أي استراتيجية تدوين ملاحظات ستكون الأكثر فعالية؟","options":["Write everything","Key points and supporting details","Only write numbers","Dont take notes"],"correct_answer":1,"explanation":"Noting key points with supporting details is most effective for academic listening"}]');
